-     * @param index  the item (zero based index).
-     * @param y  the new value (<code>null</code> permitted).
-     *
-     * @since 1.0.1
-     */
-    public void updateByIndex(int index, Number y) {
-        XYDataItem item = getDataItem(index);
-        item.setY(y);
-        fireSeriesChanged();
